sys_script_include.script:
var EmailHelpers = Class.create();

EmailHelpers.getUserSysId = function(event, current) {
    var userSysId = "";
    var eventName = event.getValue("name");
    if (
        eventName === "approval.rejected.by.other" ||
        eventName === Constants.EVENT.certificateFailedAdmin
    ) {
        userSysId = event.getValue("parm1");
    } else if (
        eventName === Constants.EVENT.requestRejected ||
        eventName === Constants.EVENT.certificateGenerated ||
        eventName === Constants.EVENT.certificateFailed ||
        eventName === Constants.EVENT.certificateDelayed
    ) {
        userSysId = current.getValue("opened_by");
    } else {
        userSysId = current.getValue("approver");
    }
    return userSysId;
};

EmailHelpers.sendCertificateFailedNotification = function(inputs) {
    var userSysId = inputs.current.getValue("opened_by");
    var userAccess = new UserAccess();
    userAccess.setUser(userSysId);

    gs.eventQueue(Constants.EVENT.certificateFailed, inputs.current, userSysId);

    if (!userAccess.isAdmin()) {
        var appAdmins = EmailHelpers.getAppAdmins();
        appAdmins.forEach(function(adminSysId) {
            gs.eventQueue(Constants.EVENT.certificateFailedAdmin, inputs.current, adminSysId);
        });
    }
};

EmailHelpers.sendCertificateGeneratedNotification = function(inputs) {
    var userSysId = inputs.current.getValue("opened_by");
    gs.eventQueue(Constants.EVENT.certificateGenerated, inputs.current, userSysId);
};

EmailHelpers.getRoleSysId = function(role) {
    var roleGr = new GlideRecord('sys_user_role');
    roleGr.addQuery('name', role);
    roleGr.query();

    if (roleGr.next()) {
        return roleGr.getValue("sys_id");
    }

    return null;
};

EmailHelpers.findAppAdmins = function(users, admins) {
    var result = [];

    for (var user in users) {
        for (var admin in admins) {
            if (users[user] === admins[admin]) {
                result.push(users[user]);
                break;
            }
        }
    }

    return result;
};

EmailHelpers.getUsersByRole = function(roleSysId) {
    var grUser = new GlideRecord('sys_user_has_role');
    grUser.addQuery('role', roleSysId);

    grUser.query();

    var users = [];

    while (grUser.next()) {
        users.push(grUser.getValue('user'));
    }

    return users;
};

EmailHelpers.getAppAdmins = function() {
    var userRoleSysId = EmailHelpers.getRoleSysId(Constants.ROLE.USER);
    var adminRoleSysId = EmailHelpers.getRoleSysId(Constants.ROLE.ADMIN);

    if (!userRoleSysId) {
        throw new Error("User role: " + userRole + " is not found!");
    }
    if (!adminRoleSysId) {
        throw new Error("Admin role: " + adminRole + " is not found!");
    }

    var users = EmailHelpers.getUsersByRole(userRoleSysId);
    var admins = EmailHelpers.getUsersByRole(adminRoleSysId);

    return EmailHelpers.findAppAdmins(users, admins);
};
